import type { Address } from "viem";
import type { Asset, DelayedIntent } from "../../sdk/index.js";
import type { PoolOperationType } from "../parse/index.js";

// 1xxx errors: the transaction is malformed and would not execute correctly
// on-chain.

/**
 * Broken `storeExpectedBalances`/`compareBalances` bracket structure:
 * `storeExpectedBalances` without a matching `compareBalances`, nested
 * brackets, or `compareBalances` without a preceding `storeExpectedBalances`.
 * We expect transactions that were generated by our frontend using router/withdrawal compressor
 **/
export const ERROR_MALFORMED_BRACKET = 1001;
/**
 * Adapter call outside a `storeExpectedBalances`/`compareBalances` bracket
 * We expect transactions that were generated by our frontend using router/withdrawal compressor,
 **/
export const ERROR_ADAPTER_CALL_OUTSIDE_BRACKET = 1002;
/**
 * Bracketed call whose target is not an adapter (or adapter that is not known to the SDK)
 **/
export const ERROR_NON_ADAPTER_CALL_IN_BRACKET = 1003;
/**
 * Bracketed adapter call cannot be replayed (undecodable/unsupported calldata)
 **/
export const ERROR_UNPREVIEWABLE_ADAPTER_CALL = 1004;
/**
 * Out-of-bracket RWA wrap/unwrap calldata cannot be decoded
 **/
export const ERROR_UNPREVIEWABLE_RWA_WRAP_UNWRAP = 1005;
/**
 * `msg.value` does not fit into the declared WETH collateral
 * Transactions can have arbitrary value, but the ones that we create
 * using our frontend should have a value that fits into the declared WETH collateral.
 **/
export const ERROR_INVALID_TRANSACTION_VALUE = 1006;

// 2xxx errors: preview limitations. The transaction itself may be fine, but
// the SDK could not fully evaluate the preview.

/** A token in the preview could not be priced by the oracle */
export const ERROR_UNPRICEABLE_TOKEN = 2001;

/**
 * Dust threshold for replayed preview balances and balance changes.
 *
 * Multicalls assembled by `CreditAccountsServiceV310` subtract a 10-unit
 * safety buffer from every expected output token in their
 * `storeExpectedBalances` deltas (`amount - 10n` in
 * `assembleStartDelayedWithdrawalCalls`/`assembleClaimDelayedCalls`), while
 * subsequent calls in the same multicall spend exact on-chain amounts. A
 * replay that credits only the min-guarantee can therefore be off by up to
 * 10 units per token, including small negative residues that are impossible
 * on-chain. Amounts within this threshold (in absolute value) are filtered
 * from preview outputs; anything beyond it is a genuine discrepancy and is
 * reported.
 */
export const PREVIEW_DUST = 10n;

/**
 * Non-throwing preview failure. When set on a preview, all fields are still
 * computed best-effort, but some of them may be unreliable.
 */
export interface OperationPreviewError {
  /**
   * Numeric http-style error code, see the `ERROR_*` constants:
   * - 1xxx: the transaction is malformed (we expect transactions
   *   that were generated by our fromtend using router/withdrawal compressor)
   *   and fields derived from replayed balances
   *   may be unreliable;
   * - 2xxx: the transaction may be fine, but the SDK could not fully
   *   evaluate the preview (e.g. a token could not be priced).
   */
  code: number;
  /**
   * Human-readable details of the specific failure
   */
  message: string;
}

export interface PoolOperationPreview {
  operation: PoolOperationType;
  /**
   * Pool address
   */
  pool: Address;
  /**
   * Token that goes from user to pool
   * In case of deposit, underlying for direct deposit, zapper input for zapper-routed deposit
   * In case of withdraw, pool shares (diesel token) for direct withdraw or zapper token out
   *
   * For mint/withdraw the amount of tokenIn cannot be determined from
   * transaction calldata alone and requires an additional async call
   * (previewMint/previewWithdraw).
   */
  tokenIn: Asset;
  /**
   * Token that goes from pool to user
   * In case of deposit, pool shares (diesel token) for direct deposit or zapper token out
   * In case of withdraw, underlying for direct withdraw or zapper token in
   *
   * For deposit/redeem the amount of tokenOut cannot be determined from
   * transaction calldata alone and requires an additional async call
   * (previewDeposit/previewRedeem).
   */
  tokenOut: Asset;
  /**
   * Set when preview encountered non-fatal errors, all fields are
   * still computed best-effort
   */
  error?: OperationPreviewError;
}

export interface OpenCreditAccountPreview {
  operation: "OpenCreditAccount" | "RWAOpenCreditAccount";
  /**
   * Credit manager the account is opened in
   */
  creditManager: Address;
  /**
   * Target token of strategy: the first quoted token, with its balance taken
   * from `assets`. Undefined when nothing is quoted.
   */
  target?: Asset;
  /**
   * Tokens that were added as collateral during account opening.
   *
   * When the transaction has native value attached, it is represented as a
   * `NATIVE_ADDRESS` entry, with the wrapped native token amount reduced
   * accordingly (omitted entirely when it reaches zero).
   */
  collateral: Asset[];
  /**
   * Sum of collateral tokens in underlying
   */
  collateralValue: bigint;
  /**
   * Borrowed amount in underlying
   */
  debt: bigint;
  /**
   * Desired quotas
   */
  quotas: Asset[];
  /**
   * Minimum amount of assets on credit account after it's opened,
   * as estimated by router
   */
  assets: Asset[];
  /**
   * Set when preview encountered non-fatal errors, all fields are
   * still computed best-effort, but derived fields (`assets`, `target`,
   * `collateralValue`) may be unreliable in that case.
   */
  error?: OperationPreviewError;
}

export interface AdjustCreditAccountPreview {
  operation: "AdjustCreditAccount";
  /**
   * Credit manager the account is opened in
   */
  creditManager: Address;
  /**
   * Credit account that is being adjusted
   */
  creditAccount: Address;
  /**
   * Tokens that were added as collateral during account opening.
   *
   * When the transaction has native value attached, it is represented as a
   * `NATIVE_ADDRESS` entry, with the wrapped native token amount reduced
   * accordingly (omitted entirely when it reaches zero).
   */
  collateralAdded: Asset[];
  /**
   * Tokens that were withdrawn as collateral during account adjustment.
   */
  collateralWithdrawn: Asset[];
  /**
   * Sum of collateral tokens in underlying
   */
  totalValue: bigint;
  /**
   * Borrowed amount in underlying
   */
  debt: bigint;
  /**
   * Debt after minus debt before
   */
  debtChange: bigint;
  /**
   * Desired quotas
   */
  quotas: Asset[];
  /**
   * Quotas after minus quotas before
   */
  quotasChange: Asset[];
  /**
   * Minimum amount of assets on credit account after the operation,
   * as estimated by router
   */
  assets: Asset[];
  /**
   * Assets after minus assets before
   */
  assetsChange: Asset[];
  /**
   * Set when preview encountered non-fatal errors, all fields are
   * still computed best-effort, but derived fields (`assets`, `assetsChange`,
   * `totalValue`) may be unreliable in that case.
   */
  error?: OperationPreviewError;
}

export interface CloseCreditAccountPreview {
  operation: "CloseCreditAccount";
  /**
   * True when the account is closed permanently (facade `closeCreditAccount`
   * entry point), false when the debt is zeroed but the account stays open
   * (plain multicall).
   */
  permanent: boolean;
  /**
   * Credit manager the account belongs to
   */
  creditManager: Address;
  /**
   * Credit account that is being closed
   */
  creditAccount: Address;
  /**
   * Underlying withdrawn to the user: minimal guaranteed amount, from the
   * multicall replay (all collateral is swapped into underlying before
   * withdrawal)
   */
  receivedAmount: bigint;
  /**
   * Set when preview encountered non-fatal errors, all fields are
   * still computed best-effort, but the
   * balance-derived `receivedAmount` may be unreliable in that case.
   */
  error?: OperationPreviewError;
}

export interface RepayCreditAccountPreview {
  operation: "RepayCreditAccount";
  /**
   * True when the account is closed permanently (facade `closeCreditAccount`
   * entry point), false when the debt is zeroed but the account stays open
   * (plain multicall).
   */
  permanent: boolean;
  /**
   * Credit manager the account belongs to
   */
  creditManager: Address;
  /**
   * Credit account that is being repaid
   */
  creditAccount: Address;
  /**
   * Tokens added from the wallet to cover the debt (`addCollateral` calls).
   *
   * When the transaction has native value attached, it is represented as a
   * `NATIVE_ADDRESS` entry, with the wrapped native token amount reduced
   * accordingly (omitted entirely when it reaches zero).
   */
  collateralAdded: Asset[];
  /**
   * Tokens returned to the user in-kind (`withdrawCollateral` calls, with the
   * MAX_UINT256 sentinel resolved against replayed balances)
   */
  collateralWithdrawn: Asset[];
  /**
   * Total debt repaid: principal + accrued interest + fees, in underlying
   */
  debtRepaid: bigint;
  /**
   * Set when preview encountered non-fatal errors, all fields are
   * still computed best-effort, but the
   * balance-derived `collateralWithdrawn` may be unreliable in that case.
   */
  error?: OperationPreviewError;
}

/**
 * Preview of the "instant" part of an operation on an existing credit
 * account: what the transaction does in the same block, before any delayed
 * withdrawal is claimed.
 */
export type InstantOperationPreview =
  | AdjustCreditAccountPreview
  | CloseCreditAccountPreview
  | RepayCreditAccountPreview;

/**
 * Preview of a multicall that requests a delayed withdrawal (e.g. Securitize
 * redemption): the source token is spent now and a withdrawal phantom token is received;
 * the actual claim token materializes later, when the withdrawal is claimed and
 * the recorded (if any) is resumed
 */
export interface DelayedCreditAccountOperationPreview {
  operation: "DelayedCreditAccountOperation";
  /**
   * Credit account the operation is performed on
   */
  creditAccount: Address;
  /**
   * Credit manager the account belongs to
   */
  creditManager: Address;
  /**
   * Decoded from the withdrawal request's extraData; undefined when the
   * request carries no intent (e.g. Mellow)
   */
  intent?: DelayedIntent;
  /**
   * What this transaction does right now: the delayed withdrawal is
   * represented by the phantom token among the account's assets
   */
  instantPreview: InstantOperationPreview;
  /**
   * Best-effort state after the withdrawal is claimed and the intent is
   * resumed; claim-only (phantom burned, claim token received) when
   * `intent` is undefined
   */
  delayedPreview: InstantOperationPreview;
}

/**
 * Result of previewing a raw operation calldata: currently pool operations and
 * credit account opening, adjustment, closure, repayment and delayed
 * withdrawal operations are supported.
 */
export type OperationPreview =
  | PoolOperationPreview
  | OpenCreditAccountPreview
  | AdjustCreditAccountPreview
  | CloseCreditAccountPreview
  | RepayCreditAccountPreview
  | DelayedCreditAccountOperationPreview;
